58	impl ChatApp {
59	    pub fn new(cc: &eframe::CreationContext<'_>, config: Config) -> Self {
60	        configure_fonts(&cc.egui_ctx, &config);
61	        apply_theme(&cc.egui_ctx, config.dark_mode);
62	        cc.egui_ctx.set_zoom_factor(config.ui_scale);
63	
64	        let runtime = tokio::runtime::Runtime::new().expect("Failed to create tokio runtime");
65	        let storage = Storage::new();
66	        let conversation_list = storage
67	            .list_conversations()
68	            .into_iter()
69	            .map(|c| (c.id, c.title))
70	            .collect();
71	
72	        let mut app = Self {
73	            messages: Vec::new(),
74	            input: String::new(),
75	            base_url: config.default_endpoint.clone(),
76	            models: Vec::new(),
77	            selected_model: 0,
78	            streaming: false,
79	            rx: None,
80	            models_rx: None,
81	            cancel_token: None,
82	            runtime,
83	            models_loading: false,
84	            error: None,
85	            system_prompt: config.system_prompt.clone(),
86	            temperature: config.temperature,
87	            max_tokens: config.max_tokens,
88	            use_max_tokens: config.use_max_tokens,
89	            dark_mode: config.dark_mode,
90	            commonmark_cache: CommonMarkCache::default(),
91	            editing_message: None,
92	            edit_buffer: String::new(),
93	            show_settings: false,
94	            storage,
95	            current_conversation_id: None,
96	            conversation_list,
97	            show_sidebar: true,
98	            show_context_sidebar: true,
99	            search_query: String::new(),
100	            search_results: Vec::new(),
101	            show_search: false,
102	            saved_endpoints: config.saved_endpoints.clone(),
103	            show_endpoints: false,
104	            new_endpoint: String::new(),
105	            new_endpoint_key: String::new(),
106	            last_usage: None,
107	            session_cost: 0.0,
108	            renaming_conversation: None,
109	            rename_buffer: String::new(),
110	            config,
111	        };
112	
113	        app.fetch_models();
114	        app
