116	
117	    fn fetch_models(&mut self) {
118	        if self.models_loading {
119	            return; // fetch already in progress
120	        }
121	        let base_url = self.base_url.clone();
122	        let api_key = self.current_api_key().map(|s| s.to_string());
123	        let (tx, rx) = mpsc::unbounded_channel();
124	
125	        self.runtime.spawn(async move {
126	            match api::fetch_models(&base_url, api_key.as_deref()).await {
127	                Ok(models) => {
128	                    let _ = tx.send(StreamEvent::ModelsLoaded(models));
129	                }
130	                Err(e) => {
131	                    let _ = tx.send(StreamEvent::Error(e));
132	                }
133	            }
134	            let _ = tx.send(StreamEvent::Done);
135	        });
136	
137	        self.models_loading = true;
138	        self.models_rx = Some(rx);
139	    }
140	
141	    fn selected_model_name(&self) -> &str {
142	        self.models
143	            .get(self.selected_model)
144	            .map(|s| s.as_str())
145	            .unwrap_or("(no models)")
146	    }
147	
148	    fn current_api_key(&self) -> Option<&str> {
149	        self.saved_endpoints
150	            .iter()
151	            .find(|ep| ep.url == self.base_url)
152	            .and_then(|ep| ep.api_key.as_deref())
153	    }
154	
155	    fn new_conversation(&mut self) {
156	        if self.streaming {
157	            self.stop_streaming();
158	        }
159	        self.save_current();
160	        self.messages.clear();
161	        self.current_conversation_id = None;
162	        self.error = None;
163	        self.last_usage = None;
164	        self.session_cost = 0.0;
165	    }
166	
167	    fn save_current(&mut self) {
168	        if self.messages.is_empty() {
169	            return;
170	        }
171	
172	        match self.current_conversation_id {
173	            Some(id) => {
174	                self.storage.save_messages(id, &self.messages);
175	            }
176	            None => {
177	                let title = self
178	                    .messages
179	                    .iter()
180	                    .find(|m| m.role == Role::User)
181	                    .map(|m| {
182	                        let t = m.content.trim();
183	                        if t.len() > 50 {
184	                            // Find a char boundary for truncation
185	                            let end = t
186	                                .char_indices()
187	                                .take_while(|(i, _)| *i <= 47)
188	                                .last()
189	                                .map(|(i, c)| i + c.len_utf8())
190	                                .unwrap_or(47);
191	                            format!("{}...", &t[..end])
192	                        } else {
193	                            t.to_string()
194	                        }
195	                    })
196	                    .unwrap_or_else(|| "New chat".to_string());
197	
198	                let id = self.storage.create_conversation(&title);
199	                self.storage.save_messages(id, &self.messages);
200	                self.current_conversation_id = Some(id);
201	            }
202	        };
203	
204	        self.refresh_conversation_list();
205	    }
206	
207	    fn load_conversation(&mut self, id: i64) {
208	        if self.streaming {
209	            self.stop_streaming();
210	        }
211	        self.save_current();
212	        self.messages = self.storage.load_messages(id);
213	        self.current_conversation_id = Some(id);
214	        self.error = None;
215	        self.last_usage = None;
216	        self.session_cost = 0.0;
217	        self.editing_message = None;
218	        self.edit_buffer.clear();
219	    }
220	
221	    fn delete_conversation(&mut self, id: i64) {
222	        self.storage.delete_conversation(id);
223	        if self.current_conversation_id == Some(id) {
224	            if self.streaming {
225	                self.stop_streaming();
226	            }
227	            self.messages.clear();
228	            self.current_conversation_id = None;
229	            self.editing_message = None;
230	            self.edit_buffer.clear();
231	        }
232	        self.refresh_conversation_list();
233	    }
234	
235	    fn refresh_conversation_list(&mut self) {
236	        self.conversation_list = self
237	            .storage
238	            .list_conversations()
239	            .into_iter()
240	            .map(|c| (c.id, c.title))
241	            .collect();
242	    }
243	
244	    fn send_message(&mut self) {
245	        let content = self.input.trim().to_string();
246	        if content.is_empty() || self.streaming || self.models.is_empty() {
247	            return;
248	        }
249	
250	        self.input.clear();
251	        self.error = None;
252	
253	        self.messages.push(Message {
254	            role: Role::User,
255	            content,
256	        });
257	
258	        self.start_streaming();
259	    }
260	
261	    fn start_streaming(&mut self) {
262	        if self.models.is_empty() {
263	            self.error = Some("No models available".to_string());
264	            return;
265	        }
266	
267	        self.messages.push(Message {
268	            role: Role::Assistant,
269	            content: String::new(),
270	        });
271	
272	        let (tx, rx) = mpsc::unbounded_channel();
273	        let cancel = CancellationToken::new();
274	        self.rx = Some(rx);
275	        self.cancel_token = Some(cancel.clone());
276	        self.streaming = true;
277	        self.last_usage = None;
278	
279	        // Clamp selected_model to valid range (saturating_sub avoids underflow on empty vec)
280	        self.selected_model = self.selected_model.min(self.models.len().saturating_sub(1));
281	        let model = self.models[self.selected_model].clone();
282	        let base_url = self.base_url.clone();
283	
284	        let mut messages: Vec<Message> = Vec::new();
285	        if !self.system_prompt.trim().is_empty() {
286	            messages.push(Message {
287	                role: Role::System,
288	                content: self.system_prompt.clone(),
289	            });
290	        }
291	        // All messages except the empty assistant one we just added
292	        messages.extend_from_slice(&self.messages[..self.messages.len() - 1]);
293	
294	        let temperature = Some(self.temperature);
295	        let max_tokens = if self.use_max_tokens {
296	            Some(self.max_tokens)
297	        } else {
298	            None
299	        };
300	
301	        let api_key = self.current_api_key().map(|s| s.to_string());
302	
303	        let params = ChatParams {
304	            base_url,
305	            model,
306	            messages,
307	            temperature,
308	            max_tokens,
309	            api_key,
310	        };
311	        self.runtime
312	            .spawn(async move { api::stream_chat(params, tx, cancel) });
313	    }
314	
315	    fn stop_streaming(&mut self) {
316	        if let Some(cancel) = self.cancel_token.take() {
317	            cancel.cancel();
318	        }
319	        self.streaming = false;
320	        self.rx = None;
321	        if let Some(last) = self.messages.last()
322	            && last.role == Role::Assistant
323	            && last.content.is_empty()
324	        {
325	            self.messages.pop();
326	        }
327	    }
328	
329	    fn regenerate(&mut self) {
330	        if self.streaming || self.models.is_empty() {
331	            return;
332	        }
333	        if let Some(last) = self.messages.last()
334	            && last.role == Role::Assistant
335	        {
336	            self.messages.pop();
337	            self.start_streaming();
338	        }
339	    }
340	
341	    fn edit_and_resend(&mut self, index: usize) {
342	        if self.streaming || index >= self.messages.len() {
343	            return;
344	        }
345	        let content = self.edit_buffer.trim().to_string();
346	        if content.is_empty() {
347	            return;
348	        }
349	
350	        self.messages[index].content = content;
351	        self.messages.truncate(index + 1);
352	        self.editing_message = None;
353	        self.edit_buffer.clear();
354	
355	        self.start_streaming();
356	    }
357	
358	    fn copy_to_clipboard(&self, text: &str) {
359	        if let Ok(mut clipboard) = arboard::Clipboard::new() {
360	            let _ = clipboard.set_text(text);
361	        }
362	    }
363	
364	    fn process_events(&mut self) {
365	        // Process model fetch events (separate channel)
366	        if let Some(rx) = &mut self.models_rx {
367	            while let Ok(event) = rx.try_recv() {
368	                match event {
369	                    StreamEvent::ModelsLoaded(models) => {
370	                        if !models.is_empty() {
371	                            self.models = models;
372	                            self.selected_model =
373	                                self.selected_model.min(self.models.len().saturating_sub(1));
374	                        }
375	                    }
376	                    StreamEvent::Done => {
377	                        self.models_loading = false;
378	                        self.models_rx = None;
379	                        break;
380	                    }
381	                    StreamEvent::Error(e) => {
382	                        self.error = Some(e);
383	                        self.models_loading = false;
384	                        self.models_rx = None;
385	                        break;
386	                    }
387	                    _ => {}
388	                }
389	            }
390	        }
391	
392	        // Process chat stream events
393	        let mut just_finished_streaming = false;
394	
395	        if let Some(rx) = &mut self.rx {
396	            while let Ok(event) = rx.try_recv() {
397	                match event {
398	                    StreamEvent::Token(token) => {
399	                        if let Some(last) = self.messages.last_mut()
400	                            && last.role == Role::Assistant
401	                        {
402	                            last.content.push_str(&token);
403	                        }
404	                    }
405	                    StreamEvent::UsageInfo(usage) => {
406	                        if let Some(cost) = usage.cost {
407	                            self.session_cost += cost;
408	                        }
409	                        self.last_usage = Some(usage);
410	                    }
411	                    StreamEvent::Done => {
412	                        just_finished_streaming = true;
413	                        self.streaming = false;
414	                        self.cancel_token = None;
415	                        self.rx = None;
416	                        break;
417	                    }
418	                    StreamEvent::Error(e) => {
419	                        self.error = Some(e);
420	                        self.streaming = false;
421	                        self.cancel_token = None;
422	                        self.rx = None;
423	                        if let Some(last) = self.messages.last()
424	                            && last.role == Role::Assistant
425	                            && last.content.is_empty()
426	                        {
427	                            self.messages.pop();
428	                        }
429	                        break;
430	                    }
431	                    _ => {}
432	                }
433	            }
434	        }
435	
436	        if just_finished_streaming && !self.messages.is_empty() {
437	            self.save_current();
438	        }
439	    }
