441	    pub fn reload_config(&mut self, ctx: &egui::Context) {
442	        let new_config = match Config::try_load() {
443	            Ok(c) => c,
444	            Err(e) => {
445	                self.error = Some(format!("Failed to reload config: {e}"));
446	                return;
447	            }
448	        };
449	
450	        // Reload fonts only if font settings actually changed
451	        let fonts_changed = self.config.font_family != new_config.font_family
452	            || self.config.mono_font_family != new_config.mono_font_family
453	            || (self.config.font_size - new_config.font_size).abs() > f32::EPSILON
454	            || (self.config.mono_font_size - new_config.mono_font_size).abs() > f32::EPSILON;
455	        if fonts_changed {
456	            configure_fonts(ctx, &new_config);
457	        }
458	
459	        // Update theme
460	        if self.dark_mode != new_config.dark_mode {
461	            self.dark_mode = new_config.dark_mode;
462	            apply_theme(ctx, self.dark_mode);
463	        }
464	
465	        // Update UI scale
466	        if (self.config.ui_scale - new_config.ui_scale).abs() > f32::EPSILON {
467	            ctx.set_zoom_factor(new_config.ui_scale);
468	        }
469	
470	        // Apply new settings
471	        self.system_prompt = new_config.system_prompt.clone();
472	        self.temperature = new_config.temperature;
473	        self.max_tokens = new_config.max_tokens;
474	        self.use_max_tokens = new_config.use_max_tokens;
475	
476	        // Capture old endpoint state for change detection
477	        let old_url = self.base_url.clone();
478	        let old_api_key = self.current_api_key().map(|s| s.to_string());
479	
480	        // Update endpoints list
481	        self.saved_endpoints = new_config.saved_endpoints.clone();
482	
483	        // Apply default_endpoint (symmetric with save which writes base_url -> default_endpoint)
484	        self.base_url = new_config.default_endpoint.clone();
485	
486	        // If the chosen endpoint isn't in the saved list, fallback to first
487	        if !self
488	            .saved_endpoints
489	            .iter()
490	            .any(|ep| ep.url == self.base_url)
491	        {
492	            if let Some(first) = self.saved_endpoints.first() {
493	                self.base_url = first.url.clone();
494	            }
495	        }
496	
497	        // Only re-fetch models if the endpoint URL or API key actually changed
498	        let new_api_key = self.current_api_key().map(|s| s.to_string());
499	        if (self.base_url != old_url || new_api_key != old_api_key) && !self.streaming {
500	            self.fetch_models();
501	        }
502	
503	        self.config = new_config;
504	        self.error = None;
505	        ctx.request_repaint();
506	    }
507	}
508	
509	fn configure_fonts(ctx: &egui::Context, config: &Config) {
510	    load_custom_fonts(ctx, config);
511	
512	    let mut style = (*ctx.global_style()).clone();
513	    style.text_styles.insert(
514	        egui::TextStyle::Body,
515	        egui::FontId::new(config.font_size, egui::FontFamily::Proportional),
516	    );
517	    style.text_styles.insert(
518	        egui::TextStyle::Monospace,
519	        egui::FontId::new(config.mono_font_size, egui::FontFamily::Monospace),
520	    );
521	    ctx.set_global_style(style);
522	}
523	
524	fn load_custom_fonts(ctx: &egui::Context, config: &Config) {
525	    use font_kit::source::SystemSource;
526	
527	    let mut fonts = egui::FontDefinitions::default();
528	    let source = SystemSource::new();
529	
530	    if !config.font_family.is_empty() {
531	        if let Some(data) = lookup_font(&source, &config.font_family) {
532	            fonts
533	                .font_data
534	                .insert("custom_proportional".to_owned(), data.into());
535	            if let Some(family) = fonts.families.get_mut(&egui::FontFamily::Proportional) {
536	                family.insert(0, "custom_proportional".to_owned());
537	            }
538	        } else {
539	            eprintln!(
540	                "Warning: font '{}' not found, using default",
541	                config.font_family
542	            );
543	        }
544	    }
545	
546	    if !config.mono_font_family.is_empty() {
547	        if let Some(data) = lookup_font(&source, &config.mono_font_family) {
548	            fonts
549	                .font_data
550	                .insert("custom_monospace".to_owned(), data.into());
551	            if let Some(family) = fonts.families.get_mut(&egui::FontFamily::Monospace) {
552	                family.insert(0, "custom_monospace".to_owned());
553	            }
554	        } else {
555	            eprintln!(
556	                "Warning: font '{}' not found, using default",
557	                config.mono_font_family
558	            );
559	        }
560	    }
561	
562	    ctx.set_fonts(fonts);
563	}
564	
565	fn lookup_font(source: &font_kit::source::SystemSource, name: &str) -> Option<egui::FontData> {
566	    use font_kit::family_name::FamilyName;
567	    use font_kit::properties::Properties;
568	
569	    let handle = source
570	        .select_best_match(&[FamilyName::Title(name.to_string())], &Properties::new())
571	        .ok()?;
572	    let font = handle.load().ok()?;
573	    let data = font.copy_font_data()?;
574	    Some(egui::FontData::from_owned((*data).clone()))
575	}
576	
577	fn apply_theme(ctx: &egui::Context, dark: bool) {
578	    if dark {
579	        ctx.set_visuals(egui::Visuals::dark());
580	    } else {
581	        ctx.set_visuals(egui::Visuals::light());
582	    }
583	}
