585	impl eframe::App for ChatApp {
586	    fn ui(&mut self, ui: &mut egui::Ui, _frame: &mut eframe::Frame) {
587	        let ctx = ui.ctx().clone();
588	        self.process_events();
589	
590	        if self.streaming || self.models_loading {
591	            ctx.request_repaint();
592	        }
593	
594	        // Keyboard shortcuts
595	        let new_chat =
596	            ui.input(|i| i.key_pressed(egui::Key::N) && (i.modifiers.ctrl || i.modifiers.command));
597	        if new_chat {
598	            self.new_conversation();
599	        }
600	
601	        // Top bar
602	        egui::Panel::top("top_bar").show_inside(ui, |ui| {
603	            ui.horizontal(|ui| {
604	                let sidebar_icon = if self.show_sidebar { "◀" } else { "▶" };
605	                if ui
606	                    .button(sidebar_icon)
607	                    .on_hover_text("Toggle sidebar")
608	                    .clicked()
609	                {
610	                    self.show_sidebar = !self.show_sidebar;
611	                }
612	
613	                ui.separator();
614	                ui.label("Model:");
615	                egui::ComboBox::from_id_salt("model_selector")
616	                    .selected_text(self.selected_model_name())
617	                    .show_ui(ui, |ui| {
618	                        for (i, model) in self.models.iter().enumerate() {
619	                            ui.selectable_value(&mut self.selected_model, i, model);
620	                        }
621	                    });
622	
623	                ui.separator();
624	                ui.label("Endpoint:");
625	
626	                if self.saved_endpoints.len() > 1 {
627	                    let mut new_url = None;
628	                    egui::ComboBox::from_id_salt("endpoint_selector")
629	                        .selected_text(&self.base_url)
630	                        .width(200.0)
631	                        .show_ui(ui, |ui| {
632	                            for ep in &self.saved_endpoints {
633	                                if ui
634	                                    .selectable_label(self.base_url == ep.url, &ep.url)
635	                                    .clicked()
636	                                {
637	                                    new_url = Some(ep.url.clone());
638	                                }
639	                            }
640	                        });
641	                    if let Some(url) = new_url {
642	                        self.base_url = url;
643	                        if !self.streaming {
644	                            self.fetch_models();
645	                        }
646	                    }
647	                } else {
648	                    ui.add(egui::TextEdit::singleline(&mut self.base_url).desired_width(200.0));
649	                }
650	
651	                if ui
652	                    .add_enabled(!self.streaming, egui::Button::new("↻"))
653	                    .on_hover_text("Refresh models")
654	                    .clicked()
655	                {
656	                    self.fetch_models();
657	                }
658	
659	                if ui.button("+").on_hover_text("Manage endpoints").clicked() {
660	                    self.show_endpoints = !self.show_endpoints;
661	                }
662	
663	                ui.separator();
664	                
665	                let context_sidebar_icon = if self.show_context_sidebar { "☰▶" } else { "☰◀" };
