1250	                                    if ui.button("Send").clicked() {
1251	                                        action = Some(MessageAction::FinishEdit(i));
1252	                                    }
1253	                                    if ui.button("Cancel").clicked() {
1254	                                        action = Some(MessageAction::CancelEdit);
1255	                                    }
1256	                                });
1257	                            } else if msg.role == Role::Assistant && !msg.content.is_empty() {
1258	                                CommonMarkViewer::new().show(
1259	                                    ui,
1260	                                    &mut self.commonmark_cache,
1261	                                    &msg.content,
1262	                                );
1263	                            } else {
1264	                                ui.label(&msg.content);
1265	                            }
1266	
1267	                            ui.add_space(8.0);
1268	                            ui.separator();
1269	                        }
1270	
1271	                        match action {
1272	                            Some(MessageAction::Copy(i)) if i < self.messages.len() => {
1273	                                self.copy_to_clipboard(&self.messages[i].content);
1274	                            }
1275	                            Some(MessageAction::StartEdit(i)) if i < self.messages.len() => {
1276	                                self.edit_buffer = self.messages[i].content.clone();
1277	                                self.editing_message = Some(i);
1278	                            }
