79	pub async fn fetch_models(base_url: &str, api_key: Option<&str>) -> Result<Vec<String>, String> {
80	    let client = Client::builder()
81	        .timeout(REQUEST_TIMEOUT)
82	        .connect_timeout(CONNECT_TIMEOUT)
83	        .build()
84	        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
85	
86	    let mut url = base_url.trim_end_matches('/').to_string();
87	
88	    // Auto-fix OpenRouter URLs (users often provide just the domain or the completions endpoint)
89	    if url.contains("openrouter.ai") {
90	        url = "https://openrouter.ai/api/v1".to_string();
91	    } else if url.ends_with("/chat/completions") {
92	        url = url.trim_end_matches("/chat/completions").to_string();
93	    }
94	
95	    // Try OpenAI-standard /v1/models first (works for OpenRouter, LM Studio, vLLM, etc.)
96	    let models_url = if url.ends_with("/v1") {
97	        format!("{url}/models")
98	    } else {
99	        format!("{url}/v1/models")
100	    };
101	
102	    let mut request = client.get(&models_url);
103	    if let Some(key) = api_key {
104	        request = request.bearer_auth(key);
105	    }
106	    if url.contains("openrouter.ai") {
107	        request = request
108	            .header("HTTP-Referer", "https://github.com/hhheath/hChat")
109	            .header("X-Title", "hChat");
110	    }
111	
112	    if let Ok(resp) = request.send().await {
113	        if resp.status().is_success() {
114	            if let Ok(openai_resp) = resp.json::<OpenAIModelsResponse>().await {
115	                let models: Vec<String> = openai_resp.data.into_iter().map(|m| m.id).collect();
116	                if !models.is_empty() {
117	                    return Ok(models);
118	                }
119	            }
120	        }
121	    }
122	
123	    // Fall back to Ollama /api/tags
124	    let api_base = url.trim_end_matches("/v1");
125	    let resp = client
126	        .get(format!("{api_base}/api/tags"))
127	        .send()
128	        .await
129	        .map_err(|e| format!("Failed to fetch models: {e}"))?;
130	
131	    let tags: OllamaTagsResponse = resp
132	        .json()
133	        .await
134	        .map_err(|e| format!("Failed to parse models: {e}"))?;
135	
136	    Ok(tags.models.into_iter().map(|m| m.name).collect())
137	}
