1	use crate::message::{Message, Role};
2	use rusqlite::{Connection, params};
3	use std::path::PathBuf;
4	
5	pub struct Conversation {
6	    pub id: i64,
7	    pub title: String,
8	}
9	
10	pub struct Storage {
11	    conn: Connection,
12	}
13	
14	impl Storage {
15	    pub fn new() -> Self {
16	        let path = Self::db_path();
17	        if let Some(parent) = path.parent() {
18	            std::fs::create_dir_all(parent).ok();
19	            #[cfg(unix)]
20	            {
21	                use std::os::unix::fs::PermissionsExt;
22	                let _ = std::fs::set_permissions(parent, std::fs::Permissions::from_mode(0o700));
23	            }
24	        }
25	        let conn = Connection::open(&path).expect("Failed to open database");
26	        // Enable foreign keys and WAL mode for better concurrency
27	        conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
28	            .ok();
29	        let storage = Self { conn };
30	        storage.init_tables();
31	        storage
32	    }
33	
34	    fn db_path() -> PathBuf {
35	        dirs::data_dir()
36	            .unwrap_or_else(|| PathBuf::from("."))
37	            .join("hchat")
38	            .join("hchat.db")
39	    }
40	
41	    fn init_tables(&self) {
42	        self.conn
43	            .execute_batch(
44	                "CREATE TABLE IF NOT EXISTS conversations (
45	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
46	                    title TEXT NOT NULL,
47	                    created_at TEXT NOT NULL DEFAULT (datetime('now')),
48	                    updated_at TEXT NOT NULL DEFAULT (datetime('now'))
49	                );
50	                CREATE TABLE IF NOT EXISTS messages (
51	                    id INTEGER PRIMARY KEY AUTOINCREMENT,
52	                    conversation_id INTEGER NOT NULL,
53	                    role TEXT NOT NULL,
54	                    content TEXT NOT NULL,
55	                    position INTEGER NOT NULL,
56	                    FOREIGN KEY (conversation_id) REFERENCES conversations(id) ON DELETE CASCADE
57	                );",
58	            )
59	            .expect("Failed to create tables");
60	    }
61	
62	    pub fn create_conversation(&self, title: &str) -> i64 {
63	        self.conn
64	            .execute(
65	                "INSERT INTO conversations (title) VALUES (?1)",
66	                params![title],
67	            )
68	            .expect("Failed to create conversation");
69	        self.conn.last_insert_rowid()
70	    }
71	
72	    pub fn update_conversation_title(&self, id: i64, title: &str) {
73	        self.conn
74	            .execute(
75	                "UPDATE conversations SET title = ?1, updated_at = datetime('now') WHERE id = ?2",
76	                params![title, id],
77	            )
78	            .ok();
79	    }
80	
81	    pub fn list_conversations(&self) -> Vec<Conversation> {
82	        let mut stmt = match self
83	            .conn
84	            .prepare("SELECT id, title FROM conversations ORDER BY updated_at DESC")
85	        {
86	            Ok(s) => s,
87	            Err(_) => return Vec::new(),
88	        };
89	
90	        match stmt.query_map([], |row| {
91	            Ok(Conversation {
92	                id: row.get(0)?,
93	                title: row.get(1)?,
94	            })
95	        }) {
96	            Ok(rows) => rows.filter_map(|r| r.ok()).collect(),
97	            Err(_) => Vec::new(),
98	        }
99	    }
100	
101	    pub fn delete_conversation(&self, id: i64) {
102	        // Use a transaction so both deletes succeed or both fail
103	        if let Ok(tx) = self.conn.unchecked_transaction() {
104	            let r1 = tx.execute(
105	                "DELETE FROM messages WHERE conversation_id = ?1",
106	                params![id],
107	            );
108	            let r2 = tx.execute("DELETE FROM conversations WHERE id = ?1", params![id]);
109	
110	            if r1.is_ok() && r2.is_ok() {
111	                tx.commit().ok();
112	            }
113	            // tx drops and rolls back on failure
114	        }
115	    }
116	
117	    pub fn save_messages(&self, conversation_id: i64, messages: &[Message]) {
118	        // Use a transaction so delete + re-insert is atomic
119	        let tx = match self.conn.unchecked_transaction() {
120	            Ok(tx) => tx,
121	            Err(_) => return,
122	        };
123	
124	        if tx
125	            .execute(
126	                "DELETE FROM messages WHERE conversation_id = ?1",
127	                params![conversation_id],
128	            )
129	            .is_err()
130	        {
131	            return; // tx rolls back on drop
132	        }
133	
134	        {
135	            let mut stmt = match tx
136	                .prepare("INSERT INTO messages (conversation_id, role, content, position) VALUES (?1, ?2, ?3, ?4)")
137	            {
138	                Ok(s) => s,
139	                Err(_) => return,
140	            };
141	
142	            for (i, msg) in messages.iter().enumerate() {
143	                let role_str = match msg.role {
144	                    Role::System => "system",
145	                    Role::User => "user",
146	                    Role::Assistant => "assistant",
147	                };
148	                if stmt
149	                    .execute(params![conversation_id, role_str, msg.content, i])
150	                    .is_err()
151	                {
152	                    return; // tx rolls back on drop
153	                }
154	            }
155	        }
156	
157	        tx.execute(
158	            "UPDATE conversations SET updated_at = datetime('now') WHERE id = ?1",
159	            params![conversation_id],
160	        )
161	        .ok();
162	
163	        tx.commit().ok();
164	    }
165	
166	    pub fn load_messages(&self, conversation_id: i64) -> Vec<Message> {
167	        let mut stmt = match self.conn.prepare(
168	            "SELECT role, content FROM messages WHERE conversation_id = ?1 ORDER BY position",
169	        ) {
170	            Ok(s) => s,
171	            Err(_) => return Vec::new(),
172	        };
173	
174	        stmt.query_map(params![conversation_id], |row| {
175	            let role_str: String = row.get(0)?;
176	            let role = match role_str.as_str() {
177	                "system" => Role::System,
178	                "user" => Role::User,
179	                "assistant" => Role::Assistant,
180	                _ => Role::Assistant,
181	            };
182	            Ok(Message {
183	                role,
184	                content: row.get(1)?,
185	            })
186	        })
187	        .map(|rows| rows.filter_map(|r| r.ok()).collect())
188	        .unwrap_or_default()
189	    }
190	
191	    pub fn search(&self, query: &str) -> Vec<(i64, String, String)> {
192	        // Escape LIKE special characters
193	        let escaped = query
194	            .replace('\\', "\\\\")
195	            .replace('%', "\\%")
196	            .replace('_', "\\_");
197	        let pattern = format!("%{escaped}%");
198	        let mut stmt = match self.conn.prepare(
199	            "SELECT c.id, c.title, m.content FROM messages m
200	             JOIN conversations c ON c.id = m.conversation_id
201	             WHERE m.content LIKE ?1 ESCAPE '\\'
202	             ORDER BY c.updated_at DESC
203	             LIMIT 50",
204	        ) {
205	            Ok(s) => s,
206	            Err(_) => return Vec::new(),
207	        };
208	
209	        stmt.query_map(params![pattern], |row| {
210	            Ok((row.get(0)?, row.get(1)?, row.get(2)?))
211	        })
