329	            current_number: Some(start_number),
330	        });
331	    }
332	
333	    pub fn start_level_without_number(&mut self) {
334	        self.items.push(ListLevel {
335	            current_number: None,
336	        });
337	    }
338	
339	    pub fn is_inside_a_list(&self) -> bool {
340	        !self.items.is_empty()
341	    }
342	
343	    pub fn is_last_level(&self) -> bool {
344	        self.items.len() == 1
345	    }
346	
347	    pub fn start_item(&mut self, ui: &mut egui::Ui, options: &CommonMarkOptions) {
348	        // To ensure that newlines are only inserted within the list and not before it
349	        if self.has_list_begun {
350	            newline(ui);
351	        } else {
352	            self.has_list_begun = true;
353	        }
354	
355	        let len = self.items.len();
356	        if let Some(item) = self.items.last_mut() {
357	            ui.label(" ".repeat((len - 1) * options.indentation_spaces));
358	
359	            if let Some(number) = &mut item.current_number {
360	                number_point(ui, &number.to_string());
361	                *number += 1;
362	            } else if len > 1 {
363	                bullet_point_hollow(ui);
364	            } else {
365	                bullet_point(ui);
366	            }
367	        } else {
368	            unreachable!();
369	        }
370	
371	        ui.add_space(4.0);
372	    }
373	
374	    pub fn end_level(&mut self, ui: &mut egui::Ui, insert_newline: bool) {
375	        self.items.pop();
376	
377	        if self.items.is_empty() && insert_newline {
378	            newline(ui);
379	        }
380	    }
