                lang: "",
                body: "plain"
            }]
        );
    }

    #[test]
    fn unclosed_fence_runs_to_end() {
        let s = "before\n```rust\nfn x()";
        let out = segments(s);
        assert_eq!(out.len(), 2);
        assert!(matches!(out[0], Segment::Markdown(_)));
        assert!(matches!(out[1], Segment::Code { lang: "rust", .. }));
    }

