        let s = "<think>\nLet me reason\n</think>\nAnswer.";
        let out = segments(s);
        assert_eq!(out.len(), 2);
        assert_eq!(
            out[0],
            Segment::Reasoning {
                body: "\nLet me reason\n",
                closed: true
            }
        );
