/// Truncate a string to at most `max_chars` characters and append `…`. Returns
/// the original string if it's already short enough. Char-aware so we never
/// slice through a multi-byte UTF-8 boundary.
fn truncate_chars(s: &str, max_chars: usize) -> String {
    if s.chars().count() <= max_chars {
        s.to_string()
    } else {
        let mut out: String = s.chars().take(max_chars).collect();
        out.push('…');
        out
    }
}

/// Format a Unix-millis timestamp as `HH:MM:SS` in the local timezone (best
/// effort — we don't pull in chrono just for hover tooltips, so this uses a
/// crude offset based on `time_t / 86400`). For Phase 1 this is good enough;
/// Phase 2 will move to proper datetime handling alongside the schema
/// migration.
fn format_timestamp(ms: i64) -> String {
    let secs = ms / 1000;
    let h = (secs / 3600) % 24;
    let m = (secs / 60) % 60;
    let s = secs % 60;
    format!("{h:02}:{m:02}:{s:02} UTC")
}

/// Render an assistant message: walk the segment list, rendering prose with
/// `egui_commonmark` and code/reasoning blocks ourselves.
fn render_assistant_message(
    ui: &mut egui::Ui,
    cache: &mut CommonMarkCache,
    msg_idx: usize,
    content: &str,
    expanded_reasoning: &mut HashSet<(usize, usize)>,
) {
    let mut span_start = 0usize;
    for seg in markdown::segments(content) {
        match seg {
            Segment::Markdown(text) => {
                CommonMarkViewer::new().show(ui, cache, text);
            }
            Segment::Code { lang, body } => {
                render_code_block(ui, lang, body);
            }
            Segment::Reasoning { body, closed } => {
                render_reasoning_block(
                    ui,
                    msg_idx,
                    span_start,
                    body,
                    closed,
                    expanded_reasoning,
                );
            }
        }
        // Advance span_start by the rendered segment's source length. We don't
        // have direct access to the source span here, so approximate by char
        // length — only used as a stable expansion key.
        span_start += match &seg {
            Segment::Markdown(t) => t.len(),
            Segment::Code { body, .. } => body.len(),
            Segment::Reasoning { body, .. } => body.len(),
        };
    }
}

fn render_code_block(ui: &mut egui::Ui, lang: &str, body: &str) {
    let visuals = ui.visuals();
    let bg = visuals.code_bg_color;
    let stroke_color = visuals.weak_text_color();

    egui::Frame::new()
        .fill(bg)
        .stroke(egui::Stroke::new(1.0, stroke_color))
        .inner_margin(egui::Margin::same(8))
        .corner_radius(4.0)
        .show(ui, |ui| {
            // Header strip: language pill (left) + copy button (right).
            ui.horizontal(|ui| {
                if !lang.is_empty() {
                    ui.label(
                        egui::RichText::new(lang)
                            .small()
                            .color(ui.visuals().weak_text_color())
                            .monospace(),
                    );
                }
                ui.with_layout(egui::Layout::right_to_left(egui::Align::Center), |ui| {
                    if ui
                        .small_button("📋")
                        .on_hover_text("Copy code")
                        .clicked()
                        && let Ok(mut cb) = arboard::Clipboard::new()
                    {
                        let _ = cb.set_text(body);
                    }
                });
            });
            ui.add(
                egui::TextEdit::multiline(&mut body.to_string())
                    .font(egui::TextStyle::Monospace)
                    .code_editor()
                    .interactive(false)
                    .frame(false)
                    .desired_width(f32::INFINITY),
            );
        });
}

fn render_reasoning_block(
    ui: &mut egui::Ui,
    msg_idx: usize,
    span_start: usize,
    body: &str,
    closed: bool,
    expanded: &mut HashSet<(usize, usize)>,
) {
    let key = (msg_idx, span_start);
    let is_open = expanded.contains(&key);
    let label = if closed {
        "💭 Reasoning"
    } else {
        "💭 Reasoning (streaming…)"
    };

    egui::CollapsingHeader::new(
        egui::RichText::new(label)
            .small()
            .color(ui.visuals().weak_text_color()),
    )
    .id_salt(("reasoning", msg_idx, span_start))
    .default_open(is_open || !closed)
    .show(ui, |ui| {
        if is_open || !closed {
            ui.label(
                egui::RichText::new(body)
                    .small()
                    .color(ui.visuals().weak_text_color()),
            );
        }
    });

    // Track open state across frames. Naive: only flips when user clicks; the
    // CollapsingHeader stores its own state internally so we only need to
    // remember the user's intent for "is open by default" decisions.
    if !closed {
        expanded.insert(key);
    }
}

