        // Central message area
        let panel_fill = ui.visuals().panel_fill;
        let mut prefill_input: Option<String> = None;
        egui::Frame::new()
            .fill(panel_fill)
            .inner_margin(egui::Margin::symmetric(16, 0))
            .show(ui, |ui| {
                // Find bar (Ctrl+F)
                if self.show_find {
                    ui.horizontal(|ui| {
                        ui.label("🔍");
                        let resp = ui.add(
                            egui::TextEdit::singleline(&mut self.find_query)
                                .hint_text("Find in conversation…")
                                .desired_width(f32::INFINITY.min(400.0)),
                        );
                        if resp.lost_focus()
                            && ui.input(|i| i.key_pressed(egui::Key::Escape))
                        {
                            self.show_find = false;
                            self.find_query.clear();
                        }
                        if !self.find_query.is_empty() {
                            let q = self.find_query.to_ascii_lowercase();
                            let matches = self
                                .messages
                                .iter()
                                .filter(|m| m.content.to_ascii_lowercase().contains(&q))
                                .count();
                            ui.weak(format!("{matches} match{}", if matches == 1 { "" } else { "es" }));
                        }
                        if ui.small_button("✕").clicked() {
                            self.show_find = false;
                            self.find_query.clear();
                        }
                    });
                    ui.separator();
                }

                egui::ScrollArea::vertical()
                    .auto_shrink([false; 2])
                    .stick_to_bottom(true)
                    .show(ui, |ui| {
                        if self.messages.is_empty() {
                            ui.vertical_centered(|ui| {
                                ui.add_space(60.0);
                                ui.heading("hChat");
                                ui.label("Lightweight local LLM chat");
                                ui.add_space(20.0);
                                ui.weak("Try one of these to get started:");
                                ui.add_space(8.0);
                                for (label, prompt) in STARTER_PROMPTS {
                                    if ui
                                        .button(*label)
                                        .on_hover_text(*prompt)
                                        .clicked()
                                    {
                                        prefill_input = Some((*prompt).to_string());
                                    }
                                }
                                ui.add_space(20.0);
                                ui.weak("Ctrl+N for new chat · Ctrl+F to find · /help for commands");
                            });
                            return;
                        }

                        let mut action: Option<MessageAction> = None;
                        let msg_count = self.messages.len();
                        let find_q_lower = if self.show_find && !self.find_query.is_empty() {
                            Some(self.find_query.to_ascii_lowercase())
                        } else {
                            None
                        };

                        for (i, msg) in self.messages.iter().enumerate() {
                            let (prefix, color) = match msg.role {
                                Role::User => ("You", egui::Color32::from_rgb(100, 180, 255)),
                                Role::Assistant => ("AI", egui::Color32::from_rgb(100, 255, 150)),
                                Role::System => ("System", egui::Color32::GRAY),
                            };

                            // Highlight messages that match find query.
                            let matches_find = find_q_lower
                                .as_deref()
                                .map(|q| msg.content.to_ascii_lowercase().contains(q))
                                .unwrap_or(false);

                            let render_message = |ui: &mut egui::Ui| {
                                ui.horizontal(|ui| {
                                    let role_resp = ui.colored_label(color, format!("{prefix}:"));
                                    if let Some(ts) = msg.created_at {
                                        role_resp.on_hover_text(format_timestamp(ts));
                                    }
                                    ui.with_layout(
                                        egui::Layout::right_to_left(egui::Align::Center),
                                        |ui| {
                                            if ui.small_button("📋").on_hover_text("Copy").clicked() {
                                                action = Some(MessageAction::Copy(i));
                                            }
                                            if msg.role == Role::User
                                                && !self.streaming
                                                && ui.small_button("✏").on_hover_text("Edit").clicked()
                                            {
                                                action = Some(MessageAction::StartEdit(i));
                                            }
                                            if msg.role == Role::Assistant
                                                && i == msg_count - 1
                                                && !self.streaming
                                                && ui
                                                    .small_button("🔄")
                                                    .on_hover_text("Regenerate")
                                                    .clicked()
                                            {
                                                action = Some(MessageAction::Regenerate);
                                            }
                                        },
                                    );
                                });

                                if self.editing_message == Some(i) {
                                    ui.add(
                                        egui::TextEdit::multiline(&mut self.edit_buffer)
                                            .desired_width(f32::INFINITY)
                                            .desired_rows(3),
                                    );
                                    ui.horizontal(|ui| {
                                        if ui.button("Send").clicked() {
                                            action = Some(MessageAction::FinishEdit(i));
                                        }
                                        if ui.button("Cancel").clicked() {
                                            action = Some(MessageAction::CancelEdit);
                                        }
                                    });
                                } else if msg.role == Role::Assistant && !msg.content.is_empty() {
                                    render_assistant_message(
                                        ui,
                                        &mut self.commonmark_cache,
                                        i,
                                        &msg.content,
                                    );
                                } else {
                                    ui.label(&msg.content);
                                }
                            };

                            if matches_find {
                                let highlight = ui.visuals().selection.bg_fill.linear_multiply(0.25);
                                let resp = egui::Frame::new()
                                    .fill(highlight)
                                    .inner_margin(egui::Margin::same(4))
                                    .corner_radius(4.0)
                                    .show(ui, render_message)
                                    .response;
                                // Scroll the first match into view
                                if Some(i)
                                    == find_q_lower.as_deref().and_then(|q| {
                                        self.messages.iter().position(|m| {
                                            m.content.to_ascii_lowercase().contains(q)
                                        })
                                    })
                                {
                                    resp.scroll_to_me(Some(egui::Align::Center));
                                }
                            } else {
                                render_message(ui);
                            }

                            ui.add_space(8.0);
                            ui.separator();
                        }

                        match action {
                            Some(MessageAction::Copy(i)) if i < self.messages.len() => {
                                self.copy_to_clipboard(&self.messages[i].content);
                            }
                            Some(MessageAction::StartEdit(i)) if i < self.messages.len() => {
                                self.edit_buffer = self.messages[i].content.clone();
                                self.editing_message = Some(i);
                            }
                            Some(MessageAction::FinishEdit(i)) => {
                                self.edit_and_resend(i);
                            }
                            Some(MessageAction::CancelEdit) => {
                                self.editing_message = None;
                                self.edit_buffer.clear();
                            }
                            Some(MessageAction::Regenerate) => {
                                self.regenerate();
                            }
                            _ => {}
                        }
                    });
            });

        if let Some(p) = prefill_input {
            self.input = p;
        }

        // Toast (auto-dismisses after 3.5s)
        if let Some((msg, started)) = self.toast.clone() {
            if started.elapsed() < std::time::Duration::from_millis(3500) {
                let screen_rect = ctx.screen_rect();
                egui::Area::new(egui::Id::new("hchat_toast"))
                    .anchor(egui::Align2::RIGHT_BOTTOM, egui::vec2(-16.0, -16.0))
                    .fixed_pos(egui::pos2(
                        screen_rect.right() - 16.0,
                        screen_rect.bottom() - 16.0,
                    ))
                    .show(&ctx, |ui| {
                        egui::Frame::popup(ui.style())
                            .inner_margin(egui::Margin::symmetric(12, 8))
                            .show(ui, |ui| {
                                ui.label(&msg);
                            });
                    });
                ctx.request_repaint_after(std::time::Duration::from_millis(200));
            } else {
                self.toast = None;
            }
        }
    }
}

