fn render_reasoning_block(
    ui: &mut egui::Ui,
    msg_idx: usize,
    block_idx: usize,
    body: &str,
    closed: bool,
) {
    let label = if closed {
        "💭 Reasoning"
    } else {
        "💭 Reasoning (streaming…)"
    };

    // Default-open while streaming so the user can watch it; collapsed once
    // closed. CollapsingHeader keeps its own state once the user clicks, so
    // that override sticks.
    egui::CollapsingHeader::new(
        egui::RichText::new(label)
            .small()
            .color(ui.visuals().weak_text_color()),
    )
    .id_salt(("reasoning", msg_idx, block_idx))
    .default_open(!closed)
    .show(ui, |ui| {
        ui.label(
            egui::RichText::new(body)
                .small()
                .color(ui.visuals().weak_text_color()),
        );
    });
}

