/// Format a Unix-millis timestamp as `HH:MM:SS` in the local timezone (best
/// effort — we don't pull in chrono just for hover tooltips, so this uses a
/// crude offset based on `time_t / 86400`). For Phase 1 this is good enough;
/// Phase 2 will move to proper datetime handling alongside the schema
/// migration.
fn format_timestamp(ms: i64) -> String {
    let secs = ms / 1000;
    let h = (secs / 3600) % 24;
    let m = (secs / 60) % 60;
    let s = secs % 60;
    format!("{h:02}:{m:02}:{s:02} UTC")
}

